module async_register(
    input clk,
    input clr,
    input en,
    input [11:0] data_in,
    output reg [11:0] data_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge clr or posedge dbg_halt) begin
    if (clr)
        data_out <= 12'b0;
    else if (en)
        data_out <= data_in;
end

endmodule
